patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 4d3de76389c2..8fff959be374 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3251,7 +3251,30 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
         if (auto *V = foldAndOrOfICmps(ICmp0, ICmp1, SI, IsAnd,
                                        /* IsLogical */ true))
           return replaceInstUsesWith(SI, V);
-  }
+
+    // select (select C, X, false), Y, false -> select C, (X && Y), false
+    // select (select C, true, X), true, Y -> select C, true, (X || Y)
+    if (auto *InnerSel = dyn_cast<SelectInst>(CondVal)) {
+      if (CondVal->hasOneUse()) {
+        Value *C = InnerSel->getCondition();
+        Value *X;
+        if (IsAnd && match(InnerSel->getFalseValue(), m_Zero())) {
+          // (C && X) && Y -> C && (X && Y)
+          X = InnerSel->getTrueValue();
+          Value *NewInner = Builder.CreateSelect(X, Op1, Zero);
+          Value *NewSel = Builder.CreateSelect(C, NewInner, Zero);
+          return replaceInstUsesWith(SI, NewSel);
+        }
+        if (!IsAnd && match(InnerSel->getTrueValue(), m_One())) {
+          // (C || X) || Y -> C || (X || Y)
+          X = InnerSel->getFalseValue();
+          Value *NewInner = Builder.CreateSelect(X, One, Op1);
+          Value *NewSel = Builder.CreateSelect(C, One, NewInner);
+          return replaceInstUsesWith(SI, NewSel);
+        }
+      }
+    }
+    }

   // select (a || b), c, false -> select a, c, false
   // select c, (a || b), false -> select c, a, false

